#include <iostream>
#include <string>

class Entity
{
public:
    virtual ~Entity()
    {
        std::cout << "~Entity" << '\n';
    }
};

class Player : public Entity
{
    std::string m_name{};

public:
    explicit Player(const std::string& name)
        : m_name{name}
    {
    }

    ~Player() override
    {
        std::cout << "~Player(" << m_name << ")" << '\n';
    }
};

int main()
{
    int n{};
    std::cin >> n;

    for (int i{0}; i < n; ++i)
    {
        std::string name{};
        std::cin >> name;
        Entity* e{new Player{name}};
        delete e;
    }

    return 0;
}

