solution_code:
#include <iostream>
#include <string>
#include <vector>

class Shape
{
public:
    virtual ~Shape()
    {
        std::cout << "~Shape" << '\n';
    }
};

class Circle : public Shape
{
    int m_r{};

public:
    explicit Circle(int r)
        : m_r{r}
    {
    }

    ~Circle() override
    {
        std::cout << "~Circle r=" << m_r << '\n';
    }
};

class Square : public Shape
{
    int m_s{};

public:
    explicit Square(int s)
        : m_s{s}
    {
    }

    ~Square() override
    {
        std::cout << "~Square s=" << m_s << '\n';
    }
};

int main()
{
    int n{};
    std::cin >> n;

    std::vector<Shape*> shapes{};
    for (int i{0}; i < n; ++i)
    {
        std::string type{};
        int value{};
        std::cin >> type >> value;
        if (type == "circle")
            shapes.push_back(new Circle{value});
        else
            shapes.push_back(new Square{value});
    }

    for (auto* s : shapes)
        delete s;

    return 0;
}
